// Evidence: httpsts-worked-http-server-ts-proxy-framing-smuggling-2
// Competency: httpsts-worked-http-server-ts-proxy-framing-smuggling-2.
// Case 7417: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: remove one trusted proxy hop and recompute authority from the socket boundary.
function worked_http_server_ts_proxy_framing_smuggling_2(trustedHops: number, contentLengthCount: number, hasTransferEncoding: boolean, insecureParser: boolean): { forward: boolean; reason: string } {
  if (trustedHops < 0 || trustedHops > 2) return { forward: false, reason: "forwarded-topology" };
  if (contentLengthCount !== 1 || hasTransferEncoding) {
    return { forward: false, reason: "ambiguous-framing" };
  }
  if (insecureParser) return { forward: false, reason: "parser-policy" };
  return { forward: true, reason: "consistent-hops" };
}

